public class Spiral {
    public static void main(String[] args) {
        int[][] m = {{1,2,3},{4,5,6},{7,8,9}};
        // print top row then right column then bottom row reversed then left column reversed
        for (int j = 0; j < 3; j++) System.out.print(m[0][j] + " ");
        for (int i = 1; i < 3; i++) System.out.print(m[i][2] + " ");
        for (int j = 1; j >= 0; j--) System.out.print(m[2][j] + " ");
        System.out.print(m[1][0]);
    }
}
